//
import { axis } from '../core/main-zc-init';
import { mathAbs } from '../core/zc-constants';
import { defined } from '../utils/zcutils';
import { getAxisObject } from './polaraxis-helpers';

let props = ['interval', 'tickCount', 'tickMultiples']; // TODO: tickMultiples

// TODO: new parser
function getPolarTickValues(options) {
    let { chartObj, type, index, config, scale, radius, plotarea, container } = options,
        tickValues;
    if (props.some(_ => defined(config[_]))) {
        let range = scale.range(),
            circumference = 2 * radius * mathAbs(range[1] - range[0]),
            axes = getAxisObject(chartObj, type, index),
            ticksObj = axis.ticks(chartObj, config, type, index, 'left', plotarea);

        axes.ticks = ticksObj;
        scale.range([0, circumference]);
        ticksObj.preCalcApproxAxisLength(plotarea);

        let tickVal = ticksObj.getTickValues(circumference, circumference, null, null, null, axes.Ticks);
        container.selectAll('g.axislabelgroup').remove();
        tickValues = tickVal.ticks;
    }

    return tickValues;
}

export { getPolarTickValues };
